INSERT INTO topic_item (topic_id, name, data) VALUES
  (3, 'Ameraucana', '{"origin":"South America", "eggColor":"Blue", "eggSize":"Large", "eggNumber":240, "temperament":["Docile and sweet", "Calm: Mostly calm", "Non-aggressive"], "description":"The Ameraucana delights backyard flocks with its unmistakable slate-blue eggs and charming bearded, muffy appearance. Friendly, adaptable and hardy, these docile birds thrive in varied climates while supplying a steady stream of medium-sized eggs, making them a favorite for families and hobbyists who appreciate both beauty and reliable production.", "imageUrl":"https://qwex.co/chicken-api/images/ameraucana.png", "sources":["https://breeds.okstate.edu/poultry/chickens/ameraucana-chickens.html", "https://robertsfarm.us/breed.php"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/7"}], "rarity":"Rare", "coldTolerance":true, "heatTolerance":true, "featherFeet":false, "purpose":"Layer Muffed, Bearded", "broody":"Occasional", "physicalVarieties":["Black", "Blue", "Blue-wheaten", "Brown-red", "Buff", "Silver", "Wheaten", "White"], "tolerance":"Cold Hardy very cold hardy", "freeRange":true, "weightStand":5.5, "weightBantam":1.6, "physicalComb":"Pea", "physicalSkin":"White", "physicalShanks":"Slate", "physicalEars":"Red", "physicalMaturing":"Moderately early maturing"}'),
  (3, 'Ancona', '{"origin":"Italy", "eggColor":"White", "eggSize":["Medium", "Large"], "eggNumber":[150], "temperament":["Highly Active", "Energetic forager", "Non-broody", "Flighty: Nervous & restless in confinement", "Flyer", "Marked wildness", "Avoids human contact"], "description":"The Ancona is instantly recognizable by its striking speckled black-and-white plumage and energetic, pheasant-like disposition, making it a lively free-range forager. Hens consistently produce around 220 medium white eggs each year while remaining non-broody and hardy in cooler climates, offering both visual appeal and solid egg production for backyard flocks.", "imageUrl":"https://qwex.co/chicken-api/images/ancona.png", "sources":["https://breeds.okstate.edu/poultry/chickens/ancona-chickens.html", "https://livestockconservancy.org/heritage-breeds/chickens/ancona/", "https://livestockconservancy.org/wp-content/uploads/2025/04/PickaBreedChickens2025-WATERMARKED.pdf", "https://robertsfarm.us/breed.php"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/22"}], "purpose":"Layer", "broody":"Non-setter", "physicalVarieties":"Black mottled, only", "rarity":"Uncommon", "tolerance":["Does well in both cold and heat", "Hardy noted for hardiness; very cold hardy except for combs"], "freeRange":true, "weightStand":4.5, "weightBantam":1.5, "physicalComb":"Single and rose", "physicalSkin":"Yellow", "physicalShanks":"Yellow", "physicalEars":"White", "physicalMaturing":"Early maturing", "weightMale":6, "weightFemale":4.5, "Brooding":"Non-Setters", "ExperienceLevel":"Novice"}'),
  (3, 'Appenzeller Spitzhauben', '{"origin":"Switzerland", "eggColor":"White", "eggSize":"Small", "eggNumber":150, "temperament":["Active", "Friendly", "Excellent foragers that dislike confinement"], "description":"The Appenzeller Spitzhauben is a rare Swiss breed celebrated for its distinctive forward-swept crest and tiny V-shaped comb that gives it a charming bonnet look. Energetic and friendly, these excellent free-range foragers love to perch in trees and produce a modest clutch of about 150 small white eggs each year.", "imageUrl":"https://qwex.co/chicken-api/images/appenzeller_spitzhauben.png", "sources":["https://en.wikipedia.org/wiki/Appenzeller_Spitzhauben"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/47"}]}'),
  (3, 'Araucana', '{"origin":"Chile", "eggColor":"Blue", "eggSize":["Medium", "Large"], "eggNumber":[200, 220], "temperament":["Friendly and inquisitive", "Good for handling", "Calm: Non-aggressive", "Note: Araucanas carry a lethal gene which causes one quarter of chicks to die in the shell."], "description":"The Araucana is a striking heritage breed from Chile, renowned for its true blue eggs that turn the shell a vivid sapphire hue. With distinctive ear-tufts, a rumpless back, and a friendly, inquisitive temperament, they are both eye-catching show birds and delightful backyard layers, producing around 220 medium-sized eggs a year.", "imageUrl":"https://qwex.co/chicken-api/images/araucana.png", "sources":["https://en.wikipedia.org/wiki/Araucana", "https://livestockconservancy.org/wp-content/uploads/2025/04/PickaBreedChickens2025-WATERMARKED.pdf", "https://robertsfarm.us/breed.php", "https://www.higheroakfarm.co.uk/araucana"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/36"}], "physicalVarieties":"Black, White, Black Breasted Red, Blue, Buff, Silver", "rarity":"Rare", "purpose":["Layer Rumpless Ear Tufts", "Study Eggs"], "broody":"Frequent", "tolerance":"Cold Hardy", "freeRange":true, "weightStand":5, "weightBantam":1.4, "physicalComb":"Pea", "physicalSkin":"Yellow", "physicalShanks":"Willow", "physicalEars":"Red", "physicalMaturing":"Moderately early maturing", "weightMale":5, "weightFemale":4}'),
  (3, 'Aseel', '{"origin":"India", "eggColor":"Brown", "eggSize":"Small", "eggNumber":[40, 150], "temperament":["Aggressive toward other chickens", "Territorial", "Docile with humans", "Aggressive: Bears confinement better than most other game breeds", "Extremely fierce & pugnacious", "Docile & easily handled when away from other cocks", "Not recommended for a mixed flock"], "description":"The Aseel is a striking, muscular game-fowl from India, renowned for its upright carriage, vibrant pea-comb, and legendary fighting spirit. While roosters are fiercely territorial with other birds, they are calm and personable with humans, and hens are devoted sitters that guard their brood zealously. Though they lay modest numbers of small light-brown eggs, their heat-tolerance, strong build, and heritage as ancestors of many modern meat breeds make them prized by experienced keepers.", "imageUrl":"https://qwex.co/chicken-api/images/aseel.png", "sources":["https://robertsfarm.us/breed.php", "https://thefarmerslamp.com/aseel-chicken/", "https://en.wikipedia.org/wiki/Aseel_(chicken)", "https://www.backyardchickens.com/threads/aseel-breed.221052/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/43"}], "rarity":"Rare", "coldTolerance":false, "heatTolerance":true, "featherFeet":false, "physicalVarieties":"Black, White, Duckwing, Red Spangled, Pyle, others", "purpose":"Game", "broody":"Can be", "tolerance":"Heat Tolerant hardy, but not feathered for cold winters; very hardy in high heat", "weightStand":5, "weightBantam":2, "physicalComb":"Pea small", "physicalSkin":"Yellow", "physicalShanks":"Yellow", "physicalEars":"Red", "physicalMaturing":"Slow to mature"}'),
  (3, 'Australorp', '{"origin":"Australia", "eggColor":"Brown", "eggSize":["Large", "Average"], "eggNumber":250, "temperament":["Gentle", "Friendly", "Calm: Docile", "More easily handled"], "description":"The Australorp, Australia''s national chicken, is celebrated for its sleek midnight-black plumage and exceptionally calm temperament. Hens are prolific layers, delivering over 250 large, light-brown eggs each year while staying gentle and easy-going, making them perfect for backyard flocks and small farms.", "imageUrl":"https://qwex.co/chicken-api/images/australorp.png", "sources":["https://robertsfarm.us/breed.php", "https://en.wikipedia.org/wiki/Australorp", "https://livestockconservancy.org/australorp-chicken/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/6"}], "rarity":"Common", "coldTolerance":true, "heatTolerance":false, "featherFeet":false, "physicalVarieties":"Black, only (standard); also blue & white", "purpose":"Dual Purpose", "broody":"Can be", "tolerance":"Hardy very hardy; very cold hardy", "freeRange":true, "weightStand":5, "weightBantam":2, "physicalComb":"Single", "physicalSkin":"White", "physicalShanks":"Dark", "physicalEars":"Red", "physicalMaturing":"Early maturing", "Behavior":"Calm: Docile; more easily handled"}'),
  (3, 'Barbu d''Uccle', '{"origin":"Belgium", "eggColor":"Cream", "eggSize":"Small", "eggNumber":175, "temperament":"Gentle and docile", "description":"The Barbu d''Uccle is a striking Belgian bantam famed for its lavish beard, feather-covered legs, and proud, upright carriage that makes it look like a tiny aristocrat. Despite its show-bird looks, it is gentle and docile, perfect for backyard flocks, and it produces a modest clutch of small, creamy eggs each year.", "imageUrl":"https://qwex.co/chicken-api/images/barbu_d_uccle.png", "sources":["https://en.wikipedia.org/wiki/Barbu_d%27Uccle", "https://chickenjournal.com/barbu-duccle-chickens/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/49"}]}'),
  (3, 'Barnevelder', '{"origin":"Netherlands", "eggColor":"Brown (Dark)", "eggSize":["Medium", "Large"], "eggNumber":[160, 250], "temperament":["Gentle", "Calm: Docile", "Good with children"], "description":"The Barnevelder, a Dutch classic, dazzles with its deep black plumage edged in metallic silver, giving a tuxedo-like sheen. Known for a calm, friendly disposition, these hens are excellent family birds and reliable layers of rich dark-brown eggs, often producing around 250 per year.", "imageUrl":"https://qwex.co/chicken-api/images/barnevelder.png", "sources":["https://robertsfarm.us/breed.php", "https://en.wikipedia.org/wiki/Barnevelder", "https://www.chickensandyou.com/barnevelder/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/14"}], "rarity":["Common", "Rare"], "coldTolerance":true, "heatTolerance":false, "featherFeet":false, "physicalVarieties":"Double-laced, Blue-laced, White, Black, others", "purpose":"Dual Purpose", "broody":"Mixed reports", "tolerance":"Less Hardy less cold hardy; developed in region known for damp conditions", "freeRange":true, "weightStand":6.5, "weightBantam":2.25, "physicalComb":"Single", "physicalSkin":"Yellow", "physicalShanks":"Yellow", "physicalEars":"Red", "physicalMaturing":"Slow to mature"}'),
  (3, 'Booted Bantam', '{"origin":"Netherlands (also developed in Belgium and Germany)", "eggColor":"White", "eggSize":"Tiny", "eggNumber":150, "temperament":"Calm and friendly", "description":"The Booted Bantam dazzles with its elegant feather-clad legs and striking \"vulture hocks,\" giving it a miniature, statuesque silhouette that shines in the show ring. These true bantams are calm, friendly companions that thrive in backyard flocks, producing a steady clutch of tiny white eggs each year.", "imageUrl":"https://qwex.co/chicken-api/images/booted_bantam.png", "sources":["https://en.wikipedia.org/wiki/Booted_Bantam", "https://poultrykeeper.com/chicken-breeds/booted-bantams/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/48"}], "conservationStatus":"Critical", "breedClass":"Heritage"}'),
  (3, 'Brahma', '{"origin":"United States (derived from Chinese stock)", "eggColor":"Brown", "eggSize":["Large", "Average"], "eggNumber":[140, 200], "temperament":["Docile", "Friendly", "Calm: Mostly gentle", "More easily handled"], "description":"The Brahma, known as the “King of All Poultry,” impresses with its massive size, feather-covered legs, and calm, friendly disposition, making it a gentle giant for backyard flocks. Hardy enough for winter, this dual-purpose bird lays up to 200 large brown eggs a year while providing generous meat, offering both productivity and personality.", "imageUrl":"https://qwex.co/chicken-api/images/brahma.png", "sources":["https://robertsfarm.us/breed.php", "https://breeds.okstate.edu/poultry/chickens/brahma-chickens.html", "https://livestockconservancy.org/brahma-chicken/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/39"}], "rarity":["Common", "Uncommon"], "coldTolerance":true, "heatTolerance":false, "featherFeet":true, "physicalVarieties":"Light, Dark, Buff", "purpose":"Dual Purpose Feather Footed, outside only", "broody":"Frequent", "tolerance":"Robust very hardy in heat & cold", "freeRange":true, "weightStand":9.5, "weightBantam":2.6, "physicalComb":"Pea", "physicalSkin":"Yellow", "physicalShanks":"Yellow", "physicalEars":"Red", "physicalMaturing":"Slow to mature"}'),
  (3, 'Bresse', '{"origin":"France (Bresse region)", "eggColor":"Cream", "eggSize":"Large", "eggNumber":260, "temperament":"Curious, active forager and sociable", "description":"Celebrated as the “queen of chickens,” the Bresse captivates with its pristine white feathers, slate-blue legs, and famed, tender meat that rivals fine cuisine. It’s also a productive layer, delivering around 260 large, creamy-colored eggs each year, while its curious, active foraging nature makes it an engaging and sociable companion for dedicated keepers.", "imageUrl":"https://qwex.co/chicken-api/images/bresse.png", "sources":["https://en.wikipedia.org/wiki/Bresse_chicken", "https://thefrugalchicken.com/bresse-chicken/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/21"}]}'),
  (3, 'Buckeye', '{"origin":"United States (Ohio)", "eggColor":"Brown", "eggSize":"Large", "eggNumber":[135, 200], "temperament":["Friendly and active", "Docile with flockmates", "Good foragers", "Roosters can be territorial", "Calm: Docile", "Can be curious", "More easily handled."], "description":"The Buckeye, Ohio’s only true American chicken, dazzles with its deep mahogany plumage, distinctive pea-comb, and cold-hardiness that thrives in harsh winters. Friendly and active, these excellent foragers and devoted mothers reliably produce 150-200 large brown eggs each year.", "imageUrl":"https://qwex.co/chicken-api/images/buckeye.png", "sources":["https://robertsfarm.us/breed.php", "https://livestockconservancy.org/buckeye-chicken/", "https://www.thefeatherbrain.com/blog/buckown-chickens"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/37"}], "rarity":["Rare", "Uncommon"], "coldTolerance":true, "heatTolerance":false, "featherFeet":true, "physicalVarieties":"Nut brown, only", "purpose":"Dual Purpose", "broody":"Can be", "tolerance":"Cold Hardy very cold hardy", "freeRange":true, "weightStand":6.5, "weightBantam":0, "physicalComb":"Pea", "physicalSkin":"Yellow", "physicalShanks":"Yellow", "physicalEars":"Red", "physicalMaturing":"Moderately slow maturing", "conservationStatus":"Watch", "breedClass":"Heritage"}'),
  (3, 'Campine', '{"origin":"Belgium", "eggColor":"White", "eggSize":["Medium", "Average"], "eggNumber":[150, 175], "temperament":["Active, curious and energetic", "Good foragers but not a cuddly lap bird", "Flighty: Flyer; alert, lively; can be curious; some are rather wild, others can be quite tolerant of humans"], "description":"The Campine’s gleaming black-and-gold laced plumage catches the eye, while its lively, inquisitive nature makes it a dynamic star of any flock. These active foragers lay up to 175 medium white eggs a year, offering both visual flair and solid egg production for hobbyists who love heritage chickens with personality.", "imageUrl":"https://qwex.co/chicken-api/images/campine.png", "sources":["https://robertsfarm.us/breed.php", "https://livestockconservancy.org/campine-chicken/", "https://www.thehappychickencoop.com/campine-chicken-breed/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/23"}], "physicalVarieties":"Golden, Silver", "rarity":"Very Rare", "purpose":"Layer Some males are hen-feathered", "broody":"Non-setter", "tolerance":"Hardy comb subject to frostbite", "freeRange":true, "weightStand":5, "weightBantam":0, "physicalComb":"Single large", "physicalSkin":"White", "physicalShanks":"Blue", "physicalEars":"White", "physicalMaturing":"Quick feathering but late maturing", "conservationStatus":"Threatened", "breedClass":"Heritage"}'),
  (3, 'Chantecler', '{"origin":"Canada", "eggColor":"Brown", "eggSize":"Large", "eggNumber":[150, 220], "temperament":["Calm and cold-hardy", "Calm: Docile, although there are reports of skittishness."], "description":"The Chantecler, Canada’s first heritage chicken, sports a distinctive tiny cushion comb that protects it from frost, making it one of the most cold-hardy breeds available. It’s a dual-purpose bird, laying around 220 large, light-brown eggs each year while offering a calm, friendly temperament that suits backyard flocks and small farms alike.", "imageUrl":"https://qwex.co/chicken-api/images/chantecler.png", "sources":["https://robertsfarm.us/breed.php", "https://livestockconservancy.org/chantecler-chicken/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/44"}], "physicalVarieties":"White, Buff, Partridge", "rarity":"Rare", "purpose":"Dual Purpose", "broody":"Frequent", "tolerance":"Cold Hardy extremely cold hardy", "weightStand":6.5, "weightBantam":0, "physicalComb":"Cushion", "physicalSkin":"Yellow", "physicalShanks":"Yellow", "physicalEars":"Red", "physicalMaturing":"Early maturing", "conservationStatus":"Watch", "breedClass":"Heritage"}'),
  (3, 'Cochin', '{"origin":"China", "eggColor":"Brown", "eggSize":"Large", "eggNumber":[140, 160], "temperament":["Gentle and broody", "Calm: Docile; more easily handled"], "description":"The Cochin is a strikingly large, heavily feathered chicken whose soft, fluffy plumage and feather-covered legs make it a show-stopper in any flock. Gentle, calm, and an excellent mother, it lays very large brown eggs—about 150 to 180 each year—while also serving as a friendly pet and reliable sit-and-hatch helper.", "imageUrl":"https://qwex.co/chicken-api/images/cochin.png", "sources":["https://robertsfarm.us/breed.php", "https://en.wikipedia.org/wiki/Cochin_chicken", "https://livestockconservancy.org/cochin-chicken/", "https://practicalselfreliance.com/cochin-chicken/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/17"}], "rarity":["Common", "Uncommon"], "coldTolerance":true, "heatTolerance":false, "featherFeet":true, "physicalVarieties":"Buff, White, Black, & Partridge", "purpose":"Fancy Feather Footed, fully", "broody":"Excellent", "tolerance":"Robust cold hardy", "freeRange":true, "weightStand":8.5, "weightBantam":1.3, "physicalComb":"Single small", "physicalSkin":"Yellow", "physicalShanks":"Yellow", "physicalEars":"Red", "physicalMaturing":"Slow to mature"}'),
  (3, 'Cream Crested Legbar', '{"origin":"United Kingdom", "eggColor":"Blue", "eggSize":"Medium", "eggNumber":190, "temperament":"Active and good-natured forager", "description":"The Cream Crested Legbar is a striking British auto-sexing layer, famed for its soft-crested pale-cream plumage and pastel blue-green eggs that add a splash of colour to any flock. Developed in the 1930s from Leghorns, Barred Plymouth Rocks and Araucanas, these active, good-natured foragers let you tell males from females at hatch while reliably producing around 190 medium-sized blue-tinted eggs each year.", "imageUrl":"https://qwex.co/chicken-api/images/cream_crested_legbar.png", "sources":["https://www.backyardchickens.com/threads/cream-crested-legbar.1342723/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/34"}], "rarity":"Rare", "coldTolerance":true, "heatTolerance":true, "featherFeet":false}'),
  (3, 'Cream Legbar', '{"origin":"United Kingdom", "eggColor":"Blue", "eggSize":"Medium", "eggNumber":200, "temperament":"Active, friendly and quiet-voiced", "description":"The Cream Legbar shines in any backyard with its self-shorn, glossy cream feathers and a proud, upright crest, while its autosexing genetics let you tell males from females the moment they hatch. Friendly, active and surprisingly quiet-voiced, these hens reliably produce about 200 medium-sized, vivid blue eggs each year, offering both visual charm and solid production for hobbyists.", "imageUrl":"https://qwex.co/chicken-api/images/cream_legbar.png", "sources":["https://en.wikipedia.org/wiki/Legbar", "https://www.roobeez.com/blog/legbar-chickens-autosexing"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/12"}], "rarity":"Rare", "coldTolerance":true, "heatTolerance":true, "featherFeet":false}'),
  (3, 'Crevecoeur', '{"origin":"France", "eggColor":"White", "eggSize":["Large", "Average"], "eggNumber":[135, 150], "temperament":["Calm and friendly", "Flighty: Active", "Can be aggressive"], "description":"The Crevecoeur is a dignified French heritage chicken renowned for its sleek black plumage, striking V-shaped comb and proud crest that lend it a regal silhouette. Calm and friendly, this dual-purpose bird reliably produces large white eggs and flavorful meat, making it an attractive choice for backyard flocks that appreciate both beauty and utility.", "imageUrl":"https://qwex.co/chicken-api/images/crevecoeur.png", "sources":["https://robertsfarm.us/breed.php", "https://livestockconservancy.org/crevecoeur-chicken/", "https://www.backyardchickens.com/articles/crevecoeur.47371/", "https://en.wikipedia.org/wiki/Crevecoeur_(chicken)"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/41"}], "physicalVarieties":"Black", "rarity":"Rare", "purpose":"Fancy Crested Bearded & muffed", "broody":"Non-setter", "tolerance":"Less Hardy because of fancy feathering, not suited for foul weather; may have problems with freezing crest feathers", "weightStand":6.5, "weightBantam":0, "physicalComb":"Horn V-shaped, duplex", "physicalSkin":"White", "physicalShanks":"White", "physicalEars":"Red", "physicalMaturing":"Moderately early maturing"}'),
  (3, 'Cubalaya', '{"purpose":"Meat, Eggs, Ornimental", "eggColor":"White", "eggSize":"Small", "weightMale":6, "weightFemale":4, "temperament":"Can be aggressive to other birds; noisy; mild-mannered compared to other game birds; friendly with people", "heatTolerance":true, "conservationStatus":"Critical", "breedClass":"Heritage"}'),
  (3, 'Delaware', '{"origin":"USA", "eggColor":"Brown", "eggSize":["Large", "Extra-Large"], "eggNumber":[175, 225], "temperament":["Calm, friendly and confident", "Calm: Docile.."], "description":"The Delaware is an eye-catching American heritage breed, instantly recognizable by its stark white feathers edged with bold black barring. Calm, friendly, and confident, these dual-purpose birds lay 200-250 large brown eggs a year while delivering excellent meat growth, making them a versatile favorite for backyard enthusiasts and small farms alike.", "imageUrl":"https://qwex.co/chicken-api/images/delaware.png", "sources":["https://chickenjournal.com/delaware-chicken/", "https://milefour.com/blogs/learn/delaware"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/38"}], "rarity":["Rare", "Uncommon"], "coldTolerance":true, "heatTolerance":false, "featherFeet":false, "physicalVarieties":"White [Columbian]", "purpose":"Dual Purpose", "broody":"Can be", "tolerance":"Robust hardy in heat & cold", "freeRange":true, "weightStand":6.5, "weightBantam":1.8, "physicalComb":"Single", "physicalSkin":"Yellow", "physicalShanks":"Yellow", "physicalEars":"Red", "physicalMaturing":"Early maturing", "conservationStatus":"Recovering", "breedClass":"Heritage"}'),
  (3, 'Dominique', '{"origin":"USA", "eggColor":"Brown", "eggSize":["Medium", "Average"], "eggNumber":250, "temperament":["Calm, genial and friendly", "Calm: Mostly calm, but more flighty than other dual purpose breeds"], "description":"The Dominique is America’s oldest heritage chicken, instantly recognizable by its striking black-and-white barred plumage and elegant rose comb. Hardy and calm, these friendly foragers not only bring a piece of colonial history to the backyard but also reliably deliver 230-275 medium brown eggs each year.", "imageUrl":"https://qwex.co/chicken-api/images/dominique.png", "sources":["https://robertsfarm.us/breed.php", "https://livestockconservancy.org/dominique-chicken/", "https://www.tractorsupply.com/tsc/cms/life-out-here/the-coop/poultry-breeds/dominique-breed-guide", "https://backyardpoultry.iamcountryside.com/chickens-101/the-delightful-dominique-chicken/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/16"}], "rarity":["Common", "Uncommon"], "coldTolerance":true, "heatTolerance":false, "featherFeet":false, "physicalVarieties":"Barred only", "purpose":"Dual Purpose", "broody":"Frequent", "tolerance":"Robust cold hardy", "freeRange":true, "weightStand":5, "weightBantam":1.5, "physicalComb":"Rose", "physicalSkin":"Yellow", "physicalShanks":"Yellow", "physicalEars":"Red", "physicalMaturing":"Early maturing", "conservationStatus":"Watch", "breedClass":"Heritage"}'),
  (3, 'Dorking', '{"origin":"England", "eggColor":"White", "eggSize":["Large", "Average"], "eggNumber":[150, 180], "temperament":["Calm, gentle and friendly; good mothers that stay with their chicks", "Calm: Docile; stately or awkward; fattens easily; more easily handled"], "description":"The Dorking, a classic English heritage breed, stands out with its rare five-toed feet and striking red earlobes, giving it a regal look on any farmyard. Calm, gentle, and devoted mothers, Dorkings lay up to 180 large white eggs a year while also providing flavorful, tender meat, making them an excellent dual-purpose choice for backyard growers and small farms alike.", "imageUrl":"https://qwex.co/chicken-api/images/dorking.png", "sources":["https://en.wikipedia.org/wiki/Dorking_chicken", "https://livestockconservancy.org/dorking-chicken/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/40"}], "physicalVarieties":"Silver Gray, White, Colored", "rarity":"Uncommon", "purpose":"Dual Purpose Five-Toed Short legs", "broody":"Great", "tolerance":"Less Hardy less hardy in general, but cold hardy", "freeRange":true, "weightStand":6.5, "weightBantam":1, "weightMale":9, "weightFemale":7, "physicalComb":"Single and rose", "physicalSkin":"White", "physicalShanks":"White", "physicalEars":"Red", "physicalMaturing":"Slow to mature", "conservationStatus":"Threatened", "breedClass":"Heritage"}'),
  (3, 'Easter Egger', '{"origin":"South America", "eggColor":"Blue, Green, Pink, Cream (varied)", "eggSize":"Medium", "eggNumber":240, "temperament":"Friendly, docile and curious", "description":"Easter Eggers are a lively mix of chickens celebrated for their surprise-filled clutches of blue, green, pink, or creamy eggs, turning every basket into a rainbow. Their friendly, curious temperament and modest size make them ideal backyard companions, while they reliably produce 200-280 medium-sized eggs each year.", "imageUrl":"https://qwex.co/chicken-api/images/easter_egger.png", "sources":["https://thriftyhomesteader.com/easter-egger-chicken/", "https://www.backyardchickens.com/articles/easter-egger-chicken.125147/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/11"}], "rarity":"Rare", "coldTolerance":false, "heatTolerance":true, "featherFeet":false}'),
  (3, 'Faverolles', '{"origin":"France", "eggColor":"Brown", "eggSize":["Medium", "Average"], "eggNumber":[180, 190], "temperament":["Docile and gentle", "Calm: Alert; very docile; genteel; prone to bullying by others, so may not do well in a mixed flock"], "description":"The French Faverolles is celebrated for its unmistakable fluffy, feather-covered legs and charming beard, giving it a teddy-bear silhouette that delights backyard keepers. Known for a gentle, sociable nature, these birds integrate well into mixed flocks while reliably producing about 180 medium-sized, light-brown eggs each year.", "imageUrl":"https://qwex.co/chicken-api/images/faverolles.png", "sources":["https://robertsfarm.us/breed.php", "https://en.wikipedia.org/wiki/Faverolles_chicken"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/18"}], "rarity":["Rare", "Uncommon"], "coldTolerance":true, "heatTolerance":false, "featherFeet":true, "physicalVarieties":"Salmon, White", "purpose":"Dual Purpose Bearded & muffed Feather footed, outside only Five-Toed", "broody":"Can be", "tolerance":"Cold Hardy because of fancy feathering, not suited for foul weather", "weightStand":7.5, "weightBantam":2.2, "physicalComb":"Single small", "physicalSkin":"White", "physicalShanks":"White", "physicalEars":"Red", "physicalMaturing":"Early maturing"}'),
  (3, 'Hamburg', '{"origin":"Germany/Netherlands", "eggColor":"White", "eggSize":["Small", "Medium"], "eggNumber":[200, 215], "temperament":["Active and flighty", "Flighty: High flyer; very flighty; spritely, active; mostly avoids human contact"], "description":"The Hamburg is a striking heritage breed celebrated for its sleek, black-and-white speckled feathers and energetic, inquisitive temperament that makes it a lively free-range forager. It consistently produces small, pristine white eggs—around 200 per year—offering both visual appeal and modest productivity for the experienced keeper who appreciates an active, flighty bird.", "imageUrl":"https://qwex.co/chicken-api/images/hamburg.png", "sources":["https://robertsfarm.us/breed.php", "https://livestockconservancy.org/hamburg-chicken/", "https://valleyhatchery.com/silver-spanged-hamburg-chickens-the-ultimate-guide-to-a-stunning-and-productive-heritage-breed/", "https://domesticanimalbreeds.com/hamburg-chicken-breed-everything-you-need-to-know/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/24"}], "rarity":["Rare", "Uncommon"], "coldTolerance":true, "heatTolerance":true, "featherFeet":false, "physicalVarieties":"Silver-Spangled, Golden-Spangled, Golden-Penciled, Silver-Penciled, White, Black", "purpose":"Eggs, Ornimental", "broody":"Non-setter", "tolerance":"Hardy", "flyingAbility":"Very Good", "freeRange":true, "weightStand":4, "weightBantam":1.5, "weightMale":5, "weightFemale":4, "physicalComb":"Rose", "physicalSkin":"White", "physicalShanks":"Slate blue", "physicalEars":"White", "physicalMaturing":"Very early maturing", "conservationStatus":"Threatened", "breedClass":"Heritage"}'),
  (3, 'Holland', '{"purpose":"Meat, Eggs", "eggColor":"White", "eggSize":"Medium", "weightMale":6, "weightFemale":4, "temperament":"Calm", "coldTolerance":true, "foragingAbility":"Good", "conservationStatus":"Critical", "breedClass":"Heritage"}'),
  (3, 'Icelandic Chicken', '{"origin":"Iceland", "eggColor":"White", "eggSize":"Medium", "eggNumber":180, "temperament":"Friendly, active and curious foragers", "description":"The Icelandic Chicken is a hardy land-race that has thrived since Viking times, enduring Iceland’s fierce winters and volcanic soils. Friendly and inquisitive, these active foragers produce a steady clutch of medium-sized white-cream eggs year-round, making them ideal for low-maintenance homesteads seeking both resilience and pleasant temperament.", "imageUrl":"https://qwex.co/chicken-api/images/icelandic_chicken.png", "sources":["https://livestockconservancy.org/icelandic-chicken/", "https://en.wikipedia.org/wiki/Icelandic_chicken"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/32"}]}'),
  (3, 'ISA Brown', '{"origin":"France", "eggColor":"Brown", "eggSize":"Large", "eggNumber":325, "temperament":"Docile and friendly", "description":"The ISA Brown is a prolific hybrid chicken renowned for its consistent production of large, rich brown eggs—often topping 300 a year—while remaining calm and quiet. Its warm, copper-tinged feathers and friendly disposition make it a favorite for backyard flocks where reliable egg supply and low noise are prized.", "imageUrl":"https://qwex.co/chicken-api/images/isa_brown.png", "sources":["https://herdnest.com/isa-brown-chicken-breed-guide/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/15"}]}'),
  (3, 'Java', '{"purpose":"Meat, Eggs", "eggColor":"Brown", "eggSize":"Large", "weightMale":9.5, "weightFemale":7.5, "temperament":"Hardy, calm", "foragingAbility":"Excellent", "freeRange":true, "conservationStatus":"Critical", "breedClass":"Heritage"}'),
  (3, 'Jersey Giant', '{"purpose":"Eggs, Meat", "eggColor":"Brown", "eggSize":"Extra Large", "weightMale":[13, 15], "weightFemale":[10, 11], "temperament":"Calm, Friendly", "conservationStatus":"Recovering", "breedClass":"Heritage"}'),
  (3, 'La Flèche', '{"purpose":"Eggs, Meat", "eggColor":"White", "eggSize":"Large", "weightMale":8, "weightFemale":6.5, "temperament":"Active", "foragingAbility":"Good", "conservationStatus":"Critical", "breedClass":"Heritage"}'),
  (3, 'Lakenvelder', '{"origin":"Germany", "eggColor":"White", "eggSize":["Small", "Medium"], "eggNumber":[150, 175], "temperament":["Active", "Flighty: Flyer; avoids human contact."], "description":"The Lakenvelder, with its tuxedo-style black and white barring, is a striking German breed that turns any flock into a living work of art. These active, hardy foragers are friendly and produce a modest clutch of small white eggs, making them perfect for keepers who prize both beauty and utility.", "imageUrl":"https://qwex.co/chicken-api/images/lakenvelder.png", "sources":["https://robertsfarm.us/breed.php", "https://en.wikipedia.org/wiki/Lakenvelder_(chicken)", "https://www.feathersite.com/Chicken/Longhorn/European/Lakenvelder.html"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/25"}], "rarity":["Rare", "Uncommon"], "coldTolerance":false, "heatTolerance":true, "featherFeet":false, "physicalVarieties":"Black/white/black pattern.", "purpose":"Layer", "broody":"Non-setter", "tolerance":"Hardy", "freeRange":true, "weightStand":4, "weightBantam":0, "physicalComb":"Single", "physicalSkin":"White", "physicalShanks":"Dark", "physicalEars":"White", "physicalMaturing":"Early maturing"}'),
  (3, 'Langshan', '{"origin":"China", "eggColor":"Brown", "eggSize":"Large", "eggNumber":[180, 200], "temperament":["Very calm and friendly, good foragers", "Flighty: Active for their size; graceful; not as calm or docile as other large breeds."], "description":"The Langshan is a tall, elegant chicken prized for its deep-brown, large eggs and flavorful white meat. Its very calm and friendly disposition makes it an excellent forager and a gentle presence in any backyard flock, while its striking mahogany plumage adds a touch of class to the coop.", "imageUrl":"https://qwex.co/chicken-api/images/langshan.png", "sources":["https://livestockconservancy.org/langshan-chicken/", "https://www.hobbyfarms.com/langshan-chicken-breed/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/35"}], "physicalVarieties":"Black, White, & Blue", "rarity":"Uncommon", "purpose":"Dual Purpose Feather Footed, outside only", "broody":"Can be", "tolerance":"Cold Hardy very hardy", "freeRange":true, "weightStand":7.5, "weightBantam":0, "physicalComb":"Single", "physicalSkin":"Grayish", "physicalShanks":"Dark", "physicalEars":"Red", "physicalMaturing":"Slow to mature"}'),
  (3, 'Leghorn', '{"origin":"Italy", "eggColor":"White", "eggSize":"Large", "eggNumber":300, "temperament":["Active, flighty, and alert", "Flighty: Economical eater; better adaptable to confinement then some Mediterranean; enjoys free range; flyer; flighty; spritely, noisy, nervous, usually avoids human contact."], "description":"The Leghorn is the ultimate high-energy white-egg layer, producing up to 300 large eggs a year while remaining light-footed and alert. Originating from Italy’s Livorno region, these bright-yellow-skinned birds thrive in free-range environments but need secure runs due to their flighty nature, making them perfect for both commercial and enthusiastic backyard flocks.", "imageUrl":"https://qwex.co/chicken-api/images/leghorn.png", "sources":["https://en.wikipedia.org/wiki/Leghorn_(chicken)"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/1"}], "rarity":"Common", "coldTolerance":false, "heatTolerance":true, "featherFeet":true, "physicalVarieties":"White, Dark Brown, Light Brown, Buff, Black, Silver, Red, Black-Tailed Red, Columbian", "purpose":"Layer", "broody":"Non-setter", "tolerance":"Heat Tolerant heat tolerant (esc. white variety); combs subject to frostbite", "freeRange":true, "weightStand":4.5, "weightBantam":1.75, "physicalComb":"Single and rose large", "physicalSkin":"Yellow", "physicalShanks":"Yellow", "physicalEars":"White", "physicalMaturing":"Very early maturing"}'),
  (3, 'Malay', '{"origin":"Southeast Asia", "eggColor":"Brown", "eggSize":"Medium", "eggNumber":60, "temperament":["Aggressive toward other birds but gentle with people", "Aggressive: Needs to be active; intolerant of close confinement; among the most aggressive, but more placid than most game birds; because of aggressiveness, not recommended for a mixed flock"], "description":"The Malay is a striking, game-type bird that towers up to 30 inches, showcasing long legs and an imposing silhouette that makes it a favorite show bird. Though it can be quarrelsome with other poultry, it is surprisingly gentle with people and thrives in hot climates, appealing to experienced keepers who value bold personality. It lays about 60 medium brown eggs each year, adding a modest production benefit to its dramatic presence.", "imageUrl":"https://qwex.co/chicken-api/images/malay.png", "sources":["https://robertsfarm.us/breed.php", "https://livestockconservancy.org/malay-chicken/", "https://en.wikipedia.org/wiki/Malay_(chicken)"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/42"}], "physicalVarieties":"Black Breasted Red, White, Spangled, Black, and Red Pyle", "rarity":"Very Rare", "purpose":"Meat, Game", "broody":"Can be", "tolerance":"Heat Tolerant hardy, but not feathered for cold winters; very hardy in heat", "heatTolerance":true, "Brooding":"Can Be", "weightStand":7, "weightBantam":0, "weightMale":9, "weightFemale":7, "physicalComb":"Strawberry", "physicalSkin":"Yellow", "physicalShanks":"Yellow", "physicalEars":"Rich red", "physicalMaturing":"Very slow to mature", "conservationStatus":"Critical", "breedClass":"Heritage"}'),
  (3, 'Marans', '{"origin":"France", "eggColor":"Brown (Dark)", "eggSize":"Large", "eggNumber":[140, 180], "temperament":["Calm, friendly and mildly broody", "Varies: Varies widely by individual and strain."], "description":"Marans chickens, hailing from the historic town of Marans in France, are celebrated for laying some of the deepest chocolate-brown eggs any breed produces, a hue that deepens as the shell ages. Calm, friendly, and only mildly broody, they reliably produce around 180 large dark brown eggs each year, making them both a practical and eye-catching addition to backyard flocks.", "imageUrl":"https://qwex.co/chicken-api/images/marans.png", "sources":["https://blog.meyerhatchery.com/2021/11/breed-spotlight-the-marans/", "https://www.thefeatherbrain.com/blog/marans-chickens"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/8"}], "rarity":["Rare", "Uncommon"], "coldTolerance":true, "heatTolerance":false, "featherFeet":true, "physicalVarieties":"Black Copper [APA], Cuckoo, and others", "purpose":"Layer Feather Footed", "broody":"Great", "tolerance":"Hardy Developed in marsh lands, so apparently tolerant of wet conditions. Some rapid and carely breeding have made some strains less hardy than others.", "weightStand":6.5, "weightBantam":2.2, "physicalComb":"Single white", "physicalSkin":"White", "physicalShanks":"White", "physicalEars":"Red"}'),
  (3, 'Modern Game', '{"purpose":"Ornamental, Exhibition", "eggColor":"White", "eggSize":"Medium", "weightMale":9, "weightFemale":7, "temperament":"Slow maturing; OK in a mixed flock", "coldTolerance":false, "conservationStatus":"Threatened", "breedClass":"Heritage"}'),
  (3, 'Naked Neck', '{"origin":"Transylvania (Romania)", "eggColor":"Brown", "eggSize":"Large", "eggNumber":[150, 190], "temperament":["Friendly and calm", "Calm: Active; docile; more easily handled"], "description":"Naked Neck chickens, also called Transylvanian Naked-Necks, are instantly recognizable by their feather-free, wrinkled neck—a trait that gives them superior heat tolerance and a striking silhouette. Friendly and calm, they are solid dual-purpose birds that reliably lay 180-200 large light-brown eggs each year while providing flavorful meat, making them a versatile favorite for backyard flocks.", "imageUrl":"https://qwex.co/chicken-api/images/naked_neck.png", "sources":["https://robertsfarm.us/breed.php", "https://en.wikipedia.org/wiki/Naked_Neck", "https://www.backyardchickens.com/articles/naked-neck-chicken-breed.19023/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/20"}], "rarity":["Rare", "Uncommon"], "coldTolerance":false, "heatTolerance":true, "featherFeet":false, "physicalVarieties":"Black, White, Red, and Red are recognized by the APA, but other varieties include Blue and Cuckoo or Barred.", "purpose":"Fancy Bare neck", "broody":"Can be", "tolerance":"Robust hardy in both cold and extreme heat", "freeRange":true, "weightStand":6, "weightBantam":1.5, "physicalComb":"Single", "physicalSkin":"Yellow", "physicalShanks":"Yellow", "physicalEars":"Red", "physicalMaturing":"Slow to mature"}'),
  (3, 'New Hampshire', '{"origin":"USA (New Hampshire)", "eggColor":"Brown", "eggSize":["Large", "Extra-Large"], "eggNumber":[210, 240], "temperament":["Docile and friendly, good with families; may become competitive around food", "Calm: Calm; can be docile or aggressive; can be curious."], "description":"The New Hampshire chicken, a robust offshoot of the Rhode Island Red, combines rapid growth with reliable egg production, making it a favorite dual-purpose bird for backyard farms. Hens lay 200-220 large brown eggs each year while remaining docile, friendly, and often pleasantly broody, ideal for families and small-scale growers. Their striking deep chestnut-red plumage adds a rustic charm to any garden setting.", "imageUrl":"https://qwex.co/chicken-api/images/new_hampshire.png", "sources":["https://robertsfarm.us/breed.php", "https://livestockconservancy.org/new-hampshire-chicken/", "https://en.wikipedia.org/wiki/New_Hampshire_chicken"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/33"}], "rarity":"Common", "coldTolerance":false, "heatTolerance":true, "featherFeet":false, "physicalVarieties":"Light brownish red, only", "purpose":"Dual Purpose", "broody":"Good", "tolerance":"Robust hardy in heat & cold; combs subject to frostbite", "freeRange":true, "weightStand":6.5, "weightBantam":1.9, "physicalComb":"Single large", "physicalSkin":"Yellow", "physicalShanks":"Yellow", "physicalEars":"Red", "physicalMaturing":"Very early maturing", "conservationStatus":"Threatened", "breedClass":"Heritage"}'),
  (3, 'Norwegian Jaerhon', '{"origin":"Norway", "eggColor":"White", "eggSize":"Medium", "eggNumber":250, "temperament":"Alert, active and good foragers; flighty and requires secure housing", "description":"The Norwegian Jaerhon, Norway’s sole native heritage chicken, is famed for its extreme cold-hardiness and energetic foraging spirit. These active, auto-sexing birds lay a reliable stream of medium-sized white eggs and thrive best in secure free-range environments where their alert, flighty nature can roam.", "imageUrl":"https://qwex.co/chicken-api/images/norwegian_jaerhon.png", "sources":["https://chickcoop.in/chicken-breed/the-norwegian-jaerhon/", "https://chickenandchicksinfo.com/jaerhon-chicken-breed-info/", "https://www.backyardchickens.com/articles/norwegian-j%C3%A6rh%C3%B8na.205406/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/30"}]}'),
  (3, 'Orpington', '{"origin":"England", "eggColor":"Brown", "eggSize":"Large", "eggNumber":[185, 210], "temperament":["Docile and friendly", "Calm: Docile; more easily handled; can be bullied"], "description":"The Orpington, especially the beloved Buff variety, is a gentle giant with plush, fluffy plumage and a calm, friendly disposition that makes it a centerpiece of any backyard flock. Renowned for its generous production of large, rich brown eggs—typically 200 to 220 a year—these birds also excel as natural brooders, providing reliable hatchlings for other breeds.", "imageUrl":"https://qwex.co/chicken-api/images/orpington.png", "sources":["https://robertsfarm.us/breed.php", "https://en.wikipedia.org/wiki/Orpington_chicken", "https://www.backyardchickens.com/threads/orpington-buff.112131/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/3"}], "rarity":"Common", "coldTolerance":true, "heatTolerance":false, "featherFeet":false, "physicalVarieties":"Buff, Black, Blue, White", "purpose":"Dual Purpose", "broody":"Good", "tolerance":"Cold Hardy very cold hardy", "freeRange":true, "weightStand":8, "weightBantam":2.2, "physicalComb":"Single", "physicalSkin":"White", "physicalShanks":"White or dark", "physicalEars":"Red", "physicalMaturing":"Moderately early maturing"}'),
  (3, 'Pekin Bantam', '{"origin":"China (popularized in the United Kingdom in the 1800s)", "eggColor":"White", "eggSize":"Tiny", "eggNumber":110, "temperament":"Docile, friendly, good with children, often broody", "description":"The Pekin Bantam charms backyard keepers with its signature feather-covered feet that resemble tiny, fluffy boots—a nod to its imperial Chinese heritage. Calm, friendly and often broody, these true bantams thrive in small spaces, offering personality over prolific laying with about 80-150 tiny white-cream eggs each year.", "imageUrl":"https://qwex.co/chicken-api/images/pekin_bantam.png", "sources":["https://en.wikipedia.org/wiki/Pekin_Bantam", "https://mygardeningjourney.com/2025/07/06/pekin-chickens/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/50"}]}'),
  (3, 'Phoenix', '{"origin":"Germany", "eggColor":"Cream", "eggSize":"Small", "eggNumber":[60, 90], "temperament":["Docile and independent", "Calm: Requires special housing or cages & high perches to accommodate long tails; generally docile"], "description":"The Phoenix dazzles with its striking, 2-5 ft long sickle-shaped tail that sweeps like a living plume, a tribute to the Japanese Onagadori but created in Germany for exhibition and backyard enjoyment. Though a modest layer of small, creamy eggs, its docile yet independent nature makes it a graceful companion for hobbyists who appreciate ornamental beauty.", "imageUrl":"https://qwex.co/chicken-api/images/phoenix.png", "sources":["https://robertsfarm.us/breed.php", "https://en.wikipedia.org/wiki/Phoenix_(chicken)", "https://livestockconservancy.org/phoenix-chicken/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/26"}], "rarity":["Rare", "Uncommon"], "coldTolerance":true, "heatTolerance":true, "featherFeet":false, "physicalVarieties":"Partridge; Silver Duckwing; White; other colors", "purpose":"Fancy Long-tailed", "broody":"Can be", "tolerance":"Less Hardy reportedly short lived; because of fancy feathering, not suited for foul weather", "weightStand":4, "weightBantam":1.75, "physicalComb":"Single", "physicalSkin":"Yellow", "physicalShanks":"Yellow or slate", "physicalEars":"Red", "physicalMaturing":"Slow to mature"}'),
  (3, 'Plymouth Rock', '{"origin":"USA", "eggColor":"Brown", "eggSize":"Large", "eggNumber":[200, 220], "temperament":["Docile, sweet, sociable and good with children", "Calm: Docile; more easily handled."], "description":"The Plymouth Rock, instantly recognizable by its classic barred black-and-white plumage, is the epitome of a friendly, hardy American chicken. It reliably produces large brown eggs—often 200–250 per year—even in colder weather, while its sweet, docile temperament makes it a favorite for families, beginners, and small farms alike.", "imageUrl":"https://qwex.co/chicken-api/images/plymouth_rock.png", "sources":["https://robertsfarm.us/breed.php", "https://livestockconservancy.org/plymouth-rock-chicken/", "https://www.backyardchickencoops.com.au/blogs/learning-centre/plymouth-rock-a-comprehensive-guide"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/5"}], "rarity":"Common", "coldTolerance":true, "heatTolerance":true, "featherFeet":false, "physicalVarieties":"Barred, White, Buff, Silver Penciled, Partridge, Columbian, Blue", "purpose":"Dual Purpose", "broody":"Infrequent", "tolerance":"Robust very cold hardy", "freeRange":true, "weightStand":7.5, "weightBantam":2.2, "physicalComb":"Single small", "physicalSkin":"Yellow", "physicalShanks":"Yellow", "physicalEars":"Red", "physicalMaturing":"Somewhat early maturing"}'),
  (3, 'Polish', '{"origin":"Poland", "eggColor":"White", "eggSize":["Small", "Average"], "eggNumber":[150, 200], "temperament":["Friendly, curious, but easily startled", "Varies: Mixed reports -- either calm or somewhat flighty; obstructed vision can hinder some activities; can be bullied; mixed reports on how well they do in a mixed flock. special care may be needed since plumage blocks vision"], "description":"Polish chickens are instantly recognizable by their spectacular feathered crests that crown their compact bodies, turning any flock into a living work of art. Though they lay a modest number of small white eggs, their friendly, curious nature and striking appearance make them perfect for backyard keepers who value personality and ornamental beauty.", "imageUrl":"https://qwex.co/chicken-api/images/polish.png", "sources":["https://robertsfarm.us/breed.php", "https://en.wikipedia.org/wiki/Polish_chicken", "https://www.backyardchickens.com/articles/polish-chicken.100894/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/19"}], "rarity":["Common", "Uncommon"], "coldTolerance":true, "heatTolerance":true, "featherFeet":true, "physicalVarieties":"Bearded & Beardless; Black, White, Golden, Silver, Buff Laced", "purpose":"Fancy Crested", "broody":"Non-setter", "tolerance":"Less Hardy some subject to health problems;, not suited for foul weather; may have problems with freezing crest feathers;", "weightStand":4.25, "weightBantam":0, "physicalComb":"V small", "physicalSkin":"White", "physicalShanks":"Blue", "physicalEars":"White"}'),
  (3, 'Rhode Island Red', '{"origin":"USA (Massachusetts & Rhode Island)", "eggColor":"Brown", "eggSize":"Large", "eggNumber":[250, 260], "temperament":["Calm and friendly; hens may be broody, roosters occasionally assertive", "Calm: Active, fairly docile, can be aggressive (cocks are especially notorious)"], "description":"The Rhode Island Red stands out as the quintessential American dual-purpose chicken, prized for its deep mahogany plumage and remarkable hardiness. Friendly yet productive, these birds lay large brown eggs—often around 250 a year—while also providing flavorful meat, making them ideal for both beginners and seasoned backyard keepers.", "imageUrl":"https://qwex.co/chicken-api/images/rhode_island_red.png", "sources":["https://robertsfarm.us/breed.php", "https://livestockconservancy.org/heritage-breeds/heritage-breeds-list/rhode-island-red-chicken/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/2"}], "rarity":"Common", "coldTolerance":true, "heatTolerance":true, "featherFeet":false, "physicalVarieties":"Red", "purpose":"Dual Purpose", "broody":"Infrequent", "tolerance":"Robust hardy in heat & cold; combs subject to frostbite", "freeRange":true, "weightStand":6.5, "weightBantam":2, "physicalComb":"Single and rose large", "physicalSkin":"Yellow", "physicalShanks":"Yellow", "physicalEars":"Red", "physicalMaturing":"Moderately early maturing"}'),
  (3, 'Rhode Island White', '{"conservationStatus":"Watch", "breedClass":"Heritage"}'),
  (3, 'Serama', '{"origin":"Malaysia", "eggColor":"White", "eggSize":"Tiny", "eggNumber":200, "temperament":"Friendly, calm, confident, and easily handled", "description":"The Serama, celebrated as the world''s smallest chicken, stands proudly with its upright posture and bold, confident demeanor. Originating from Kelantan, Malaysia, these pint-sized bantams come in a dazzling array of colors, are exceptionally friendly and easy to handle, and even though they lay tiny white-cream eggs, they reward owners with a lively, personable pet.", "imageUrl":"https://qwex.co/chicken-api/images/serama.png", "sources":["https://en.wikipedia.org/wiki/Serama", "https://www.backyardchickens.com/articles/serama.47258/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/29"}]}'),
  (3, 'Silkie', '{"origin":"China", "eggColor":"White", "eggSize":"Small", "eggNumber":[80, 100], "temperament":["Docile and curious", "Calm: Docile; because of size and docility, may not do well in a mixed flock"], "description":"Silkies are instantly recognizable by their plush, down-like plumage and striking black skin, giving them a cuddly, teddy-bear appearance that captivates backyard enthusiasts. Their gentle, curious temperament and strong broodiness make them superb pets and natural incubators, while their modest production of about 100 small, creamy-white eggs adds a charming bonus to any flock.", "imageUrl":"https://qwex.co/chicken-api/images/silkie.png", "sources":["https://robertsfarm.us/breed.php", "https://en.wikipedia.org/wiki/Silkie", "https://www.thefeatherbrain.com/blog/silkie-chickens"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/4"}], "rarity":["Rare", "Common"], "coldTolerance":false, "heatTolerance":true, "featherFeet":true, "physicalVarieties":"Bearded & Beardless; Black, White, Blue, Buff, Partridge, Gray", "purpose":"Bantam", "broody":"Best", "tolerance":"Hardy hardy in heat & cold; because of fancy feathering, not suited for foul weather", "weightStand":0, "weightBantam":2.2, "physicalComb":"Walnut", "physicalSkin":"Black", "physicalShanks":"Black", "physicalEars":"Turquoise", "physicalMaturing":"Slow to mature"}'),
  (3, 'Sultan', '{"origin":"Turkey", "eggColor":"White", "eggSize":"Small", "eggNumber":[55, 175], "temperament":["Gentle and friendly, active yet calm", "Calm: Non-aggressive; more easily handled"], "description":"The Sultan chicken is a true show-stopper, famed for its towering feathered crest, luxurious ten-inch white tail, and the unique feather-covered five-toed feet that give it a regal, almost mythical appearance. Beneath the flamboyant plumage lies a gentle, friendly bird that enjoys a calm backyard life and contributes a modest handful of small white eggs each year, making it perfect for fanciers who prize beauty and a pleasant temperament.", "imageUrl":"https://qwex.co/chicken-api/images/sultan.png", "sources":["https://robertsfarm.us/breed.php", "https://en.wikipedia.org/wiki/Sultan_chicken", "https://livestockconservancy.org/sultan-chicken/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/45"}], "rarity":["Rare", "Uncommon"], "coldTolerance":false, "heatTolerance":true, "featherFeet":true, "physicalVarieties":"White, only", "purpose":"Ornamental", "broody":"Non-setter", "tolerance":"Less Hardy not suited for foul weather; may have problems with freezing crest feathers", "weightStand":4, "weightBantam":0, "weightMale":6, "weightFemale":4, "physicalComb":"Horn V-shaped, duplex", "physicalSkin":"White", "physicalShanks":"White", "physicalEars":"White [hidden under", "physicalMaturing":"Moderately slow developing", "conservationStatus":"Threatened", "breedClass":"Heritage"}'),
  (3, 'Sumatra', '{"origin":"Indonesia", "eggColor":"White", "eggSize":"Small", "eggNumber":[100, 120], "temperament":["Flighty and active", "Flighty: Needs to be active; intolerant of close confinement; strong fliers if given the opportunity; can be quite wild, but can be tamed."], "description":"The Sumatra is a striking heritage chicken with jet-black, iridescent plumage and a long, pheasant-like tail that shimmers with green and purple hues. Retaining wild characteristics such as black skin and multiple spurs, it is a lively, flighty bird prized by enthusiasts for its exotic appearance and historical pedigree, producing a modest clutch of small white eggs.", "imageUrl":"https://qwex.co/chicken-api/images/sumatra.png", "sources":["https://robertsfarm.us/breed.php", "https://livestockconservancy.org/sumatra-chicken/", "https://en.wikipedia.org/wiki/Sumatra_chicken"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/27"}], "rarity":["Rare", "Uncommon"], "coldTolerance":true, "heatTolerance":true, "featherFeet":false, "physicalVarieties":"Black (and Blue as of 2010 for standard, earlier for bantams)", "purpose":"Game", "broody":"Can be", "tolerance":"Heat Tolerant not feathered for cold winters; hardy in heat", "weightStand":4, "weightBantam":0, "physicalComb":"Pea small, tiny or no wattles", "physicalSkin":"Yellow", "physicalShanks":"Purply black", "physicalEars":"Dark purply red"}'),
  (3, 'Sussex', '{"origin":"England (Sussex, Kent, Surrey)", "eggColor":"Brown", "eggSize":"Large", "eggNumber":[200, 225], "temperament":["Calm, curious, friendly", "Calm: Gentle; active; can be curious; more easily handled"], "description":"The Sussex is a classic English dual-purpose breed celebrated for its calm, curious temperament and reliable production. Hens lay large, tan-to-brown eggs at a steady rate of 200-250 a year, while the birds'' sturdy build and flavorful meat make them a favorite for both backyard hobbyists and small farms.", "imageUrl":"https://qwex.co/chicken-api/images/sussex.png", "sources":["https://robertsfarm.us/breed.php", "https://livestockconservancy.org/sussex-chicken/", "https://www.thehappychickencoop.com/speckled-sussex/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/9"}], "rarity":["Common", "Uncommon"], "coldTolerance":true, "heatTolerance":false, "featherFeet":false, "physicalVarieties":"Speckled, Red, Light", "purpose":"Dual Purpose", "broody":"Good", "tolerance":"Robust very cold hardy", "freeRange":true, "weightStand":7, "weightBantam":2.2, "physicalComb":"Single", "physicalSkin":"White", "physicalShanks":"White", "physicalEars":"Red", "physicalMaturing":"Moderately early maturing"}'),
  (3, 'Swedish Flower Hen', '{"origin":"Sweden", "eggColor":"Brown (Light)", "eggSize":"Large", "eggNumber":175, "temperament":"Calm and friendly", "description":"The Swedish Flower hen enchants with its mille-fleur speckled plumage, a dark canvas dotted with countless tiny flower-like spots that make it one of the most decorative birds in any flock. Calm, friendly, and hardy, this Swedish landrace thrives in free-range settings and reliably lays 150-200 large light-brown eggs each year, offering striking beauty without demanding upkeep.", "imageUrl":"https://qwex.co/chicken-api/images/swedish_flower_hen.png", "sources":["https://www.backyardchickens.com/threads/swedish-flower-hen-skaensk-blommehona.839807/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/31"}]}'),
  (3, 'Welsummer', '{"origin":"Netherlands", "eggColor":"Brown (Dark)", "eggSize":"Large", "eggNumber":180, "temperament":"Calm and friendly", "description":"The Welsummer dazzles backyard flocks with its striking partridge-gold plumage and deep chocolate-brown eggs that look like tiny candies. Calm, friendly, and good for free-range living, this medium-sized dual-purpose bird offers reliable, large-sized egg production while also providing satisfying meat yields for both new and seasoned keepers.", "imageUrl":"https://qwex.co/chicken-api/images/welsummer.png", "sources":["https://www.dineachook.com.au/blog/breed-profile-welsummer-chickens/", "https://www.backyardchickencoops.com.au/blogs/learning-centre/welsummer-a-comprehensive-guide"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/13"}], "rarity":"Common", "coldTolerance":true, "heatTolerance":true, "featherFeet":false}'),
  (3, 'Wyandotte', '{"origin":"USA", "eggColor":"Brown", "eggSize":"Large", "eggNumber":[190, 225], "temperament":["Calm, confident, friendly and moderately dominant", "Calm:"], "description":"The Wyandotte is a striking American dual-purpose bird, known for its glossy, laced plumage and a low-profile rose comb that tolerates frost. Calm, confident and friendly, they excel in colder climates while delivering a steady supply of 200-250 large, light-brown eggs each year, making them a beloved choice for both egg-centric homesteads and small-scale meat production.", "imageUrl":"https://qwex.co/chicken-api/images/wyandotte.png", "sources":["https://robertsfarm.us/breed.php", "https://mannapro.com/blogs/news/wyandotte-chicken-breed-profile-a-handsome-homestead-favorite", "https://chickenjournal.com/wyandotte-chicken/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/10"}], "rarity":["Rare", "Common"], "coldTolerance":true, "heatTolerance":false, "featherFeet":false, "physicalVarieties":"Silver Laced, Golden Laced, White, Buff, Partridge, Silvered Penciled, Columbian", "purpose":"Dual Purpose", "broody":"Infrequent", "tolerance":"Robust very cold hardy", "freeRange":true, "weightStand":6.5, "weightBantam":2.2, "physicalComb":"Rose", "physicalSkin":"Yellow", "physicalShanks":"Yellow", "physicalEars":"Red", "physicalMaturing":"Moderately early maturing"}'),
  (3, 'Yokohama', '{"origin":"Japan (refined in Germany)", "eggColor":"Cream", "eggSize":"Small", "eggNumber":80, "temperament":["Calm and friendly, exhibition-oriented", "Calm: Requires special housing or cages & high perches to accommodate long tails; generally docile; cocks can be pugnacious around other cocks; because of special needs, not recommended for a mixed flock"], "description":"The Yokohama dazzles with its spectacular, sweeping tail that can trail several feet behind, turning any backyard into a living exhibition. Bred from Japanese long-tailed fowl and refined in Germany, these calm, friendly birds lay modest clutches of small, cream-tinted eggs, making them ideal for hobbyists who value ornamental beauty over high production.", "imageUrl":"https://qwex.co/chicken-api/images/yokohama.png", "sources":["https://robertsfarm.us/breed.php", "https://en.wikipedia.org/wiki/Yokohama_chicken", "https://livestockconservancy.org/yokohama-chicken/", "https://poultrykeeper.com/chicken-breeds/yokohama-chickens/"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/28"}], "rarity":["Rare", "Very Rare"], "coldTolerance":false, "heatTolerance":true, "featherFeet":false, "physicalVarieties":"Red shouldered & white; White; other colors", "purpose":"Fancy Long-tailed", "broody":"Can be", "tolerance":"Less Hardy because of fancy feathering, not suited for foul weather", "freeRange":false, "weightStand":4, "weightBantam":0, "physicalComb":"Walnut or pea", "physicalSkin":"Yellow", "physicalShanks":"Yellow", "physicalEars":"White", "physicalMaturing":"Slow to mature"}'),
  (3, 'Yokohama Red', '{"origin":"Germany (from Japanese long-tailed imports)", "eggColor":"Cream", "eggSize":"Small", "eggNumber":85, "temperament":"Docile and calm", "description":"The Yokohama Red dazzles with its vivid copper-red shoulder plumage and a spectacular, sweeping tail that can trail several feet behind—a true show-bird masterpiece. Known for a gentle, calm demeanor, this ornamental hen adds striking color to any backyard while laying a modest clutch of small, creamy eggs each year.", "imageUrl":"https://qwex.co/chicken-api/images/yokohama_red.png", "sources":["https://en.wikipedia.org/wiki/Yokohama_chicken"], "links":[{"rel":"self", "href":"http://chickenapi.com/api/v1/breeds/46"}], "rarity":"Rare", "coldTolerance":false, "heatTolerance":false, "featherFeet":false}');
