  (4, 'Magpie', '{"imageUrl":"https://www.metzerfarms.com/images/products/magpies/magpie-male.jpg", "experienceLevel":null, "purpose":null, "physicalColor":"White with black markings", "temperament":"4.5", "flyingAbility":"None", "foragingAbility":"Good", "motheringAbility":"Good", "eggSize":"65-72", "eggNumber":"120-180", "bluishEggs":"20%", "fertilityRate":"86%", "weight":"4.50-6.00", "APAClass":"Medium", "showQuality":"", "conservationStatus":"Threatened", "origin":"England", "notes":null, "sources":["https://www.metzerfarms.com/compare-duck-breeds.html", "https://www.metzerfarms.com/images/id_chart/Metzer_Farms_BreedIDSheet_compressed.pdf"]}'),
  (4, 'Mallard', '{"imageUrl":"https://www.metzerfarms.com/images/products/mallard-ducks/mallard-cp.jpg", "experienceLevel":null, "purpose":null, "physicalColor":"Brown, Males have green heads", "temperament":"5.0", "flyingAbility":"Very Good", "foragingAbility":"Very Good", "motheringAbility":"Very Good", "eggSize":"65-75", "eggNumber":"60-120", "bluishEggs":"70%", "fertilityRate":"90%", "weight":"2.25-2.50", "APAClass":"Bantam", "showQuality":"Too \"Chunky\"", "conservationStatus":"Abundant", "origin":"North America", "notes":null, "sources":["https://www.metzerfarms.com/compare-duck-breeds.html", "https://www.metzerfarms.com/images/id_chart/Metzer_Farms_BreedIDSheet_compressed.pdf"]}'),
  (4, 'Muscovy-Black', '{"imageUrl":"https://www.metzerfarms.com/images/products/black-muscovy-ducks/BlackMuscovyAdults.jpg", "experienceLevel":null, "purpose":null, "physicalColor":"Black", "temperament":"1.0", "flyingAbility":"Excellent", "foragingAbility":"Excellent", "motheringAbility":"Excellent", "eggSize":"75-85", "eggNumber":"100-150", "bluishEggs":"0%", "fertilityRate":"90%", "weight":"6.50-13.00", "APAClass":"Heavy", "showQuality":"Average", "conservationStatus":"No Rank", "origin":"South America", "notes":null, "sources":["https://www.metzerfarms.com/compare-duck-breeds.html", "https://www.metzerfarms.com/images/id_chart/Metzer_Farms_BreedIDSheet_compressed.pdf"]}'),
