  (10, 'Berkshire', '{"imageUrl":"https://www.britishpigs.org.uk/images/2020/01/31/berkshire-main.jpg", "conservationStatus":null, "temperament":null, "weightMale":null, "weightFemale":null, "weightHarvest":null, "litterSize":null, "motheringAbility":null, "foragingAbility":null, "experienceLevel":null, "origin":null, "sources":[]}'),
  (10, 'Choctaw', '{"imageUrl":"https://livestockconservancy.org/wp-content/uploads/2022/08/white-choctaw-sow-600x416.jpg", "conservationStatus":"Critical", "temperament":"Aggressive", "weightMale":"250-300", "weightFemale":"150-200", "weightHarvest":"150-180", "litterSize":6, "motheringAbility":"Excellent", "foragingAbility":"Excellent", "experienceLevel":"Intermediate", "origin":"United States", "sources":["https://livestockconservancy.org/wp-content/uploads/2025/01/PickaBreedPigs2024-A-WATERMARKED.pdf"], "notes":"Hogs descended from Spanish stocks kept by the Choctaw Nation; adaptable; independent"}'),
  (10, 'Duroc', '{"imageUrl":"https://www.britishpigs.org.uk/images/2020/03/03/duroc-main.jpg", "conservationStatus":null, "temperament":null, "weightMale":null, "weightFemale":null, "weightHarvest":null, "litterSize":null, "motheringAbility":null, "foragingAbility":null, "experienceLevel":null, "origin":null, "sources":[]}'),
  (10, 'Gloucestershire Old Spot', '{"imageUrl":"https://www.britishpigs.org.uk/images/2020/02/19/gloucestershire-old-spot-main.jpg", "conservationStatus":"Threatened", "temperament":"Docile", "weightMale":"500-600", "weightFemale":"450-500", "weightHarvest":"260-280", "litterSize":10, "motheringAbility":"Good-Excellent", "foragingAbility":"Good", "experienceLevel":"Novice-Intermediate", "origin":"England", "sources":["https://livestockconservancy.org/wp-content/uploads/2025/01/PickaBreedPigs2024-A-WATERMARKED.pdf"], "notes":"Lop eared orchard pigs; hardy; sows should have 14 teats for large litters; white skin can burn from overexposure to sun"}'),
  (10, 'Guinea Hog', '{"imageUrl":"https://livestockconservancy.org/wp-content/uploads/2022/08/Guinea-Hog-Boar-600x292.jpg", "conservationStatus":"Threatened", "temperament":"Docile", "weightMale":"250-300", "weightFemale":"150", "weightHarvest":"150-180", "litterSize":"4-8", "motheringAbility":"Good-Excellent", "foragingAbility":"Good", "experienceLevel":"Novice", "origin":"United States", "sources":["https://livestockconservancy.org/wp-content/uploads/2025/01/PickaBreedPigs2024-A-WATERMARKED.pdf"], "notes":"One of the smallest breeds; excellent for homesteading; easy keepers that can be prone to obesity, so free choice feed is not recommended"}'),
  (10, 'Hampshire', '{"imageUrl":"https://www.britishpigs.org.uk/images/2020/04/30/hampshire-breed.jpg", "conservationStatus":null, "temperament":null, "weightMale":null, "weightFemale":null, "weightHarvest":null, "litterSize":null, "motheringAbility":null, "foragingAbility":null, "experienceLevel":null, "origin":null, "sources":[]}'),
