  (10, 'Idaho Pasture Pig (IPP)', '{"imageUrl":null, "conservationStatus":null, "temperament":"Friendly and curious disposition", "weightMale":"350-450", "weightFemale":"250-350", "weightHarvest":null, "litterSize":"8-10", "motheringAbility":null, "foragingAbility":null, "experienceLevel":null, "origin":"United States", "sources":["https://atmhomestead.com/breed-standards"]}'),
  (10, 'Kune Kune', '{"imageUrl":"https://www.kunekunebreeders.com/img.php?src=%2Fuploads%2Fimages%2F11-20260307-164208-734b4df7.webp", "conservationStatus":null, "temperament":"Calm, well-tempered lard pigs", "weightMale":"200-250", "weightFemale":"100-175", "weightHarvest":null, "litterSize":null, "motheringAbility":null, "foragingAbility":"Excellent", "experienceLevel":null, "origin":"New Zealand", "notes":"Heritage breeds, slow-growing, pasture pigs, Lard pigs", "sources":["https://www.redridgefarm.org/post/the-top-homestead-heritage-pig-breeds-for-small-scale-farming"]}'),
  (10, 'Landrace', '{"imageUrl":"https://www.britishpigs.org.uk/images/2020/02/18/british-landrace-breed.jpg", "conservationStatus":null, "temperament":null, "weightMale":null, "weightFemale":null, "weightHarvest":null, "litterSize":null, "motheringAbility":null, "foragingAbility":null, "experienceLevel":null, "origin":null, "sources":[]}'),
  (10, 'Large Black', '{"imageUrl":"https://www.britishpigs.org.uk/images/2020/02/25/large-black-main.jpg", "conservationStatus":"Critical", "temperament":"Docile", "weightMale":"700-800", "weightFemale":"500-600", "weightHarvest":"230-240", "litterSize":"8-10", "motheringAbility":"Good-Excellent", "foragingAbility":"Good", "experienceLevel":"Novice-Intermediate", "origin":"England", "sources":["https://livestockconservancy.org/wp-content/uploads/2025/01/PickaBreedPigs2024-A-WATERMARKED.pdf"], "notes":"Lop eared; hardy; selected to have 14 teats to support large litters; can put on enormous amounts of fat"}'),
  (10, 'Mangalitza', '{"imageUrl":"https://www.britishpigs.org.uk/images/2020/04/29/mangalitza-breed-page.jpg", "conservationStatus":null, "temperament":null, "weightMale":null, "weightFemale":null, "weightHarvest":null, "litterSize":null, "motheringAbility":null, "foragingAbility":null, "experienceLevel":null, "origin":null, "sources":[]}'),
  (10, 'Meishan', '{"imageUrl":"https://livestockconservancy.org/wp-content/uploads/2022/08/Meishan-Sow-and-Piglet-600x401.jpg", "conservationStatus":"Threatened", "temperament":"Docile", "weightMale":"275-375", "weightFemale":"300-400", "weightHarvest":"220-275", "litterSize":"16-20", "motheringAbility":"Excellent", "foragingAbility":"Good", "experienceLevel":"Intermediate", "origin":"China", "sources":["https://livestockconservancy.org/wp-content/uploads/2025/01/PickaBreedPigs2024-A-WATERMARKED.pdf"], "notes":"Thrive on a diet higher in fiber and roughage; an extremely docile and sedentary breed."}'),
  (10, 'Mulefoot', '{"imageUrl":"https://livestockconservancy.org/wp-content/uploads/2022/08/mulefoot-sows-600x436.jpg", "conservationStatus":"Critical", "temperament":"Active, but docile", "weightMale":"400-600", "weightFemale":"400-600", "weightHarvest":"250-260", "litterSize":"5-6 up to 12", "motheringAbility":"Excellent", "foragingAbility":"Excellent", "experienceLevel":"Novice", "origin":"United States", "sources":["https://livestockconservancy.org/wp-content/uploads/2025/01/PickaBreedPigs2024-A-WATERMARKED.pdf"], "notes":"Erect to semi-lop ears; has solid hooves that may be advantageous in wet conditions"}'),
  (10, 'Ossabaw Island', '{"imageUrl":"https://livestockconservancy.org/wp-content/uploads/2022/08/Ossabaw-Island-Hogs-600x338.jpg", "conservationStatus":"Critical", "temperament":"Varies by herd", "weightMale":"250-350", "weightFemale":"150-250", "weightHarvest":"175", "litterSize":"4-8", "motheringAbility":"Excellent", "foragingAbility":"Excellent", "experienceLevel":"Novice-Intermediate", "origin":"United States", "sources":["https://livestockconservancy.org/wp-content/uploads/2025/01/PickaBreedPigs2024-A-WATERMARKED.pdf"], "notes":"Thrifty and self-sufficient; highly social breed; sows often protect piglets as a group; sensitive to high levels of sugar in diet"}'),
  (10, 'Pietrain', '{"imageUrl":"https://www.britishpigs.org.uk/images/2020/04/30/pietrain-breed-page.jpg", "conservationStatus":null, "temperament":null, "weightMale":null, "weightFemale":null, "weightHarvest":null, "litterSize":null, "motheringAbility":null, "foragingAbility":null, "experienceLevel":null, "origin":null, "sources":[]}'),
  (10, 'Red Wattle', '{"imageUrl":"https://livestockconservancy.org/wp-content/uploads/2022/08/Red-Wattle-sow-600x480.jpg", "conservationStatus":"Threatened", "temperament":"Docile", "weightMale":"700-800", "weightFemale":"500-600", "weightHarvest":"260-280", "litterSize":"8-12", "motheringAbility":"Excellent", "foragingAbility":"Good", "experienceLevel":"Novice", "origin":"United States", "sources":["https://livestockconservancy.org/wp-content/uploads/2025/01/PickaBreedPigs2024-A-WATERMARKED.pdf"], "notes":"Very fertile breed; rapid growth rate"}'),
  (10, 'Tamworth', '{"imageUrl":"https://www.britishpigs.org.uk/images/2020/02/26/tamworth-main.jpg", "conservationStatus":"Recovering", "temperament":"Active, but docile", "weightMale":"500-600", "weightFemale":"500-600", "weightHarvest":"250-260", "litterSize":"6-10", "motheringAbility":"Excellent", "foragingAbility":"Excellent", "experienceLevel":"Novice-Intermediate", "origin":"Ireland", "sources":["https://livestockconservancy.org/wp-content/uploads/2025/01/PickaBreedPigs2024-A-WATERMARKED.pdf"], "notes":"Erect ears; long lean body; one of the more athletic breeds"}'),
  (10, 'Yorkshire', '{"imageUrl":"https://www.britishpigs.org.uk/images/2020/02/25/large-white-main.jpg", "conservationStatus":null, "temperament":null, "weightMale":null, "weightFemale":null, "weightHarvest":null, "litterSize":null, "motheringAbility":null, "foragingAbility":null, "experienceLevel":null, "origin":null, "sources":[]}');
